// Store for authorization codes: code -> { client_id, redirect_uri, user, expires_at, scope, code_challenge, code_challenge_method }
const authorizationCodes = new Map();

// Store for access tokens: token -> { client_id, user, expires_at, scope }
const accessTokens = new Map();

// Store for refresh tokens: token -> { client_id, user, scope }
const refreshTokens = new Map();

// Utility functions
function generateCode() {
  return crypto.randomBytes(32).toString('hex');
}

function generateToken() {
  return crypto.randomBytes(64).toString('hex');
}

function cleanupExpired() {
  const now = Date.now();
  for (const [code, data] of authorizationCodes) {
    if (data.expires_at < now) {
      authorizationCodes.delete(code);
    }
  }
  for (const [token, data] of accessTokens) {
    if (data.expires_at < now) {
      accessTokens.delete(token);
    }
  }
}

// Run cleanup every 5 minutes
setInterval(cleanupExpired, 5 * 60 * 1000);

// Validate client
function validateClient(client_id, redirect_uri) {
  const client = registeredClients[client_id];
  if (!client) return { valid: false, error: 'Unknown client_id' };
  if (redirect_uri && !client.redirect_uris.includes(redirect_uri)) {
    return { valid: false, error: 'Invalid redirect_uri' };
  }
  return { valid: true, client };
}

// PKCE support
function verifyCodeChallenge(code_verifier, code_challenge, method) {
  if (method === 'S256') {
    const hash = crypto.createHash('sha256').update(code_verifier).digest();
    const computed = hash.toString('base64url');
    return computed === code_challenge;
  } else if (method === 'plain') {
    return code_verifier === code_challenge;
  }
  return false;
}

