// POST /authorize/decision - Handle consent decision
app.post('/authorize/decision', (req, res) => {
  const { decision } = req.body;

  if (!req.session.user || !req.session.authRequest) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'No active session or authorization request' });
  }

  const { client_id, redirect_uri, state, scope, code_challenge, code_challenge_method } = req.session.authRequest;

  if (decision !== 'allow') {
    // User denied - redirect back with error
    const params = new URLSearchParams({
      error: 'access_denied',
      error_description: 'The user denied the authorization request',
      state
    });
    delete req.session.authRequest;
    return res.redirect(`${redirect_uri}?${params.toString()}`);
  }

  // Generate authorization code
  const code = generateCode();
  const codeData = {
    client_id,
    redirect_uri,
    user: req.session.user,
    scope,
    expires_at: Date.now() + 10 * 60 * 1000, // 10 minutes
    code_challenge,
    code_challenge_method,
    used: false
  };

  authorizationCodes.set(code, codeData);

  // Clean up auth request from session (keep user session for SSO)
  delete req.session.authRequest;

  // Redirect back to client with authorization code
  const params = new URLSearchParams({ code, state });
  res.redirect(`${redirect_uri}?${params.toString()}`);
});

// POST /token - Token endpoint
app.post('/token', (req, res) => {
  const { grant_type } = req.body;

  if (grant_type === 'authorization_code') {
    return handleAuthorizationCodeGrant(req, res);
  } else if (grant_type === 'refresh_token') {
    return handleRefreshTokenGrant(req, res);
  } else {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: 'Supported grant types: authorization_code, refresh_token'
    });
  }
});

function handleAuthorizationCodeGrant(req, res) {
  const { code, redirect_uri, client_id, client_secret, code_verifier } = req.body;

  // Also support client credentials in Authorization header
  let authClientId = client_id;
  let authClientSecret = client_secret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString();
    const [headerClientId, headerClientSecret] = decoded.split(':');
    authClientId = headerClientId;
    authClientSecret = headerClientSecret;
  }

  if (!code) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Authorization code is required' });
  }

  if (!authClientId) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'client_id is required' });
  }

  // Validate client
  const client = registeredClients[authClientId];
  if (!client) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Unknown client' });
  }

  // Look up authorization code
  const codeData = authorizationCodes.get(code);
  if (!codeData) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid or expired authorization code' });
  }

  // Check if code was already used (prevent replay attacks)
  if (codeData.used) {
    // Revoke all tokens issued with this code
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code has already been used' });
  }

  // Validate code hasn't expired
  if (codeData.expires_at < Date.now()) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code has expired' });
  }

  // Validate client_id matches
  if (codeData.client_id !== authClientId) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Client ID mismatch' });
  }

  // Validate redirect_uri matches
  if (redirect_uri && codeData.redirect_uri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Redirect URI mismatch' });
  }

  // PKCE verification
  if (codeData.code_challenge) {
    if (!code_verifier) {
      return res.status(400).json({ error: 'invalid_request', error_description: 'code_verifier is required for PKCE' });
    }
    const method = codeData.code_challenge_method || 'plain';
    if (!verifyCodeChallenge(code_verifier, codeData.code_challenge, method)) {
      return res.status(400).json({ error: 'invalid_grant', error_description: 'PKCE verification failed' });
    }
  } else {
    // No PKCE, require client_secret
    if (client.client_secret !== authClientSecret) {
      return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
    }
  }

  // Mark code as used
  codeData.used = true;

  // Generate tokens
  const accessToken = generateToken();
  const refreshToken = generateToken();
  const expiresIn = 3600; // 1 hour

  accessTokens.set(accessToken, {
    client_id: authClientId,
    user: codeData.user,
    scope: codeData.scope,
    expires_at: Date.now() + expiresIn * 1000
  });

  refreshTokens.set(refreshToken, {
    client_id: authClientId,
    user: codeData.user,
    scope: codeData.scope
  });

  // Remove used authorization code
  authorizationCodes.delete(code);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: expiresIn,
    refresh_token: refreshToken,
    scope: codeData.scope
  });
}

function handleRefreshTokenGrant(req, res) {
  const { refresh_token, client_id, client_secret } = req.body;

  let authClientId = client_id;
  let authClientSecret = client_secret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString();
    const [headerClientId, headerClientSecret] = decoded.split(':');
    authClientId = headerClientId;
    authClientSecret = headerClientSecret;
  }

  if (!refresh_token) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'refresh_token is required' });
  }

  const tokenData = refreshTokens.get(refresh_token);
  if (!tokenData) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid refresh token' });
  }

  // Validate client
  const client = registeredClients[authClientId];
  if (!client || client.client_secret !== authClientSecret) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
  }

  if (tokenData.client_id !== authClientId) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Client ID mismatch' });
  }

  // Rotate refresh token
  refreshTokens.delete(refresh_token);

  const newAccessToken = generateToken();
  const newRefreshToken = generateToken();
  const expiresIn = 3600;

  accessTokens.set(newAccessToken, {
    client_id: authClientId,
    user: tokenData.user,
    scope: tokenData.scope,
    expires_at: Date.now() + expiresIn * 1000
  });

  refreshTokens.set(newRefreshToken, {
    client_id: authClientId,
    user: tokenData.user,
    scope: tokenData.scope
  });

  res.json({
    access_token: newAccessToken,
    token_type: 'Bearer',
    expires_in: expiresIn,
    refresh_token: newRefreshToken,
    scope: tokenData.scope
  });
}

// GET /userinfo - UserInfo endpoint (protected resource)
app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Bearer token required' });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Invalid or expired access token' });
  }

  if (tokenData.expires_at < Date.now()) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'invalid_token', error_description: 'Access token has expired' });
  }

  const scopes = tokenData.scope.split(' ');
  const userInfo = { sub: tokenData.user.username };

  if (scopes.includes('profile')) {
    userInfo.name = tokenData.user.name;
    userInfo.role = tokenData.user.role;
    userInfo.preferred_username = tokenData.user.username;
  }

  if (scopes.includes('email')) {
    userInfo.email = tokenData.user.email;
    userInfo.email_verified = true;
  }

  res.json(userInfo);
});

// POST /token/introspect - Token introspection endpoint (RFC 7662)
app.post('/token/introspect', (req, res) => {
  const { token, client_id, client_secret } = req.body;

  // Authenticate the requesting client
  let authClientId = client_id;
  let authClientSecret = client_secret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString();
    const [headerClientId, headerClientSecret] = decoded.split(':');
    authClientId = headerClientId;
    authClientSecret = headerClientSecret;
  }

  const client = registeredClients[authClientId];
  if (!client || client.client_secret !== authClientSecret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (!token) {
    return res.json({ active: false });
  }

  const tokenData = accessTokens.get(token);
  if (!tokenData || tokenData.expires_at < Date.now()) {
    return res.json({ active: false });
  }

  res.json({
    active: true,
    scope: tokenData.scope,
    client_id: tokenData.client_id,
    username: tokenData.user.username,
    token_type: 'Bearer',
    exp: Math.floor(tokenData.expires_at / 1000),
    iat: Math.floor((tokenData.expires_at - 3600000) / 1000),
    sub: tokenData.user.username
  });
});

// POST /token/revoke - Token revocation endpoint (RFC 7009)
app.post('/token/revoke', (req, res) => {
  const { token, token_type_hint, client_id, client_secret } = req.body;

  let authClientId = client_id;
  let authClientSecret = client_secret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString();
    const [headerClientId, headerClientSecret] = decoded.split(':');
    authClientId = headerClientId;
    authClientSecret = headerClientSecret;
  }

  const client = registeredClients[authClientId];
  if (!client || client.client_secret !== authClientSecret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (token) {
    if (token_type_hint === 'refresh_token') {
      refreshTokens.delete(token);
    } else {
      accessTokens.delete(token);
    }
    // Try both just in case
    accessTokens.delete(token);
    refreshTokens.delete(token);
  }

  // Always return 200 per RFC 7009
  res.status(200).send();
});

